/* ============ HELPERS ============ */
const $=s=>document.querySelector(s);
const esc=s=>String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
function toast(m,demo){const t=$('#toast');t.innerHTML='<i class="ti ti-circle-check"></i> '+esc(m)+(demo?'<span class="demo-tag">DEMO</span>':'');t.classList.add('show');clearTimeout(t._t);t._t=setTimeout(()=>t.classList.remove('show'),2600);}
const ini=n=>n.split(' ').slice(0,2).map(w=>w[0]).join('').toUpperCase();
const roleName={estudiante:'Estudiante',coordinacion:'Coordinación'};
const pendJ=()=>state.reservas.filter(r=>r.tipo==='jaguar'&&r.estado==='Pendiente').length;
const sportMeta=s=>SPORTS.find(x=>x.k===s||x.space===s)||SPORTS[0];
const llegaron=r=>r.parts.filter(p=>p.s==='Asistió').length;
const faltan=r=>r.parts.filter(p=>p.s!=='Asistió').length;

